    ],
    "비결정_또는_미확정": [
      {
        "항목": "README 설치 절차 검토",
        "내용": "목요일까지 가능하면 검토 제안되었으나 담당자 미지정"
      },
      {
        "항목": "Hara 점검 일정",
        "내용": "Minjun의 스모크 결과 공유 후 타르볼 경로 확인, 정확한 마감시각 미설정"
      }
    ],
    "리스크": [
      "타르볼 경로 오류 시 릴리스 지연 가능",
      "README 설치 절차가 최신이 아니면 릴리스 노트가 사용자에게 오해를 줄 수 있음"
    ],
    "오픈_질문": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 스트레치 목표를 명시해야 하는가?"
    ]
  },
